BLE "documents" USING fts5(title, content, tokenize = \'trigram\')',         "question": "After what season did the number 7 competitor retire ?",         "blendsql": """         {{             LLMQA(                 'When did the competitor retire?',                 (                     SELECT documents.title AS 'Competitor', documents.content FROM documents                     JOIN {{                         LLMJoin(                             left_on='w::rider',                             right_on='documents::title'                         )                     }}                     WHERE w.no = 7                 )             )         }}         """,     },     {         "serialized_db": 'CREATE TABLE "w" (\n"index" INTEGER,\n  "year" TEXT,\n  "winner" TEXT,\n  "position" TEXT,\n  "school" TEXT\n)\n/*\n3 example rows:\nSELECT * FROM w LIMIT 3\n index    year         winner   position     school\n     0 1961-62       ron ryan right wing      colby\n     1 1962-63 bob brinkworth     center rensselaer\n     2 1963-64 bob brinkworth     center rensselaer\n*/\n\nCREATE VIRTUAL TABLE "documents" USING fts5(title, content, tokenize = \'trigram\')',         "question": "What year was the 1971-72 ECAC Hockey Player of the Year born ?",         "blendsql": """         {{             LLMQA(                 'What year was the player born?',                 (                     SELECT documents.title AS 'Player', documents.content FROM documents                     JOIN {{                         LLMJoin(                             left_on = 'w::winner',                             right_on = 'documents::title'                         )                     }}                     WHERE w.year = '1971-72'                 )             )         }}         """,     },     {         "serialized_db": 'CREATE TABLE "w" (\n"index" INTEGER,\n  "date" TEXT,\n  "language" TEXT,\n  "language family" TEXT,\n  "region" TEXT\n)\n/*\n3 example rows:\nSELECT * FROM w LIMIT 3\n index                     date language language family      region\n     0 early 2nd millennium bce sumerian         isolate mesopotamia\n     1       2nd millennium bce  eblaite         semitic       syria\n     2            ca . 1100 bce  hittite       anatolian    anatolia\n*/\n\nCREATE VIRTUAL TABLE "documents" USING fts5(title, content, tokenize = \'trigram\')',         "question": "What was the language family that was used in Hattusa , as well as parts of the northern Levant and Upper Mesopotamia ?",         "blendsql": """         SELECT "language family" FROM w         WHERE language = {{             LLMQA(                 'Which language was used in Hattusa, as well as parts of the northern Levant and Upper Mesopotamia ?',                 (SELECT title, content FROM documents WHERE documents MATCH 'hattusa'),                 options='w::language'             )         }}        """,     }, ] In [3]: Copied! <pre># 2) Define our prompt to the Parser LLM
class ParserProgram(Program):
    def __call__(self, examples: List[dict], serialized_db: str, question: str, **kwargs):
        with self.systemcontext:
            self.model += dedent("""
            Generate BlendSQL given the question, table, and passages to answer the question correctly.
            BlendSQL is a superset of SQLite, which adds external function calls for information not found within native SQLite.
            These external functions should be wrapped in double curly brackets.

            If question-relevant column(s) contents are not suitable for SQL comparisons or calculations, map it to a new column with clean content by a new grammar:
                `LLMMap('question', '{table}::{column}')`

            If mapping to a new column still cannot answer the question with valid SQL, turn to an end-to-end solution using a new grammar:
                `LLMQA('{question}', ({blendsql}))`

            If we need to do a `join` operation where there is imperfect alignment between table values, use the new grammar:
                `LLMJoin(({blendsql}), options='{table}::{column}')`

            ONLY use these BlendSQL ingredients if necessary.
            Answer parts of the question in vanilla SQL, if possible.

            Examples:\n
            """)
            for example in examples:
                self.model += f"{example['serialized_db']}\n\n"
                self.model += f"Question: {example['question']}\n"
                self.model += f"BlendSQL: {example['blendsql']}\n"
        with self.usercontext:
            self.model += f"{serialized_db}\n\n"
            self.model += f"Question: {question}\n"
            self.model += f"BlendSQL: "
        with self.assistantcontext:
            self.model += gen(name="result", **self.gen_kwargs)
        return self.model
