    # 3) Call the parser with our prompt
    res = parser.predict(
        program=ParserProgram,
        serialized_db=db.to_serialized(),
        question=question,
        examples=examples
    )
    query = res["result"]
    # 4) Execute the BlendSQL query to get the final answer
    smoothie = blend(
        query=query,
        db=db,
        ingredients={LLMMap, LLMQA, LLMJoin},
        verbose=False,
        blender=blender
    )
    return (query, smoothie)
